-- A-Level Computer Science Flashcards (OCR + AQA)
-- Generated for the RAG Learning study app from existing notes HTML files.
-- One INSERT per topic. card_order restarts at 1 within each topic.

-- ---------------------------------------------------------------
-- Schema migration: add 'level' column if not present (idempotent)
-- ---------------------------------------------------------------
ALTER TABLE flashcards ADD COLUMN IF NOT EXISTS level TEXT DEFAULT 'alevel'
  CHECK (level IN ('gcse','as','alevel'));


